define('taoMediaManager/qtiCreator/renderers/Figure',['lodash', 'taoQtiItem/qtiCommonRenderer/renderers/Figure', 'taoMediaManager/qtiCreator/widgets/static/figure/Widget'], function (_, Figure, FigureWidget) {
  'use strict';

  var CreatorFigure = _.clone(Figure);
  CreatorFigure.render = function (figure, options) {
    var imageElem = _.find(figure.getBody().elements, elem => elem.is('img'));
    options = options || {};
    options.baseUrl = this.getOption('baseUrl');
    options.uri = this.getOption('uri');
    options.lang = this.getOption('lang');
    options.mediaManager = this.getOption('mediaManager');
    options.assetManager = this.getAssetManager();
    options.state = imageElem.metaData.widget && imageElem.metaData.widget.getCurrentState().name;
    FigureWidget.build(figure, Figure.getContainer(figure), this.getOption('bodyElementOptionForm'), options);
  };
  return CreatorFigure;
});
