define('taoMediaManager/qtiCreator/editor/propertiesPanel',['jquery', 'taoQtiItem/qtiCreator/helper/panel', 'taoMediaManager/qtiCreator/editor/styleEditor/styleEditor', 'taoMediaManager/qtiCreator/editor/styleEditor/styleSheetToggler', 'taoMediaManager/qtiCreator/editor/styleEditor/fontSelector', 'taoMediaManager/qtiCreator/editor/styleEditor/colorSelector', 'taoMediaManager/qtiCreator/editor/styleEditor/fontSizeChanger'], function ($, panel, styleEditor, styleSheetToggler, fontSelector, colorSelector, fontSizeChanger) {
  'use strict';
  return function setUpInteractionPanel($container, widget, config) {
    panel.initSidebarAccordion($container);
    panel.initFormVisibilityListener();
    var elementClass = {
      elementClass: styleEditor.getMainClass()
    };
    config = Object.assign(config, elementClass);
    styleEditor.init(widget.element, config);
    styleSheetToggler.init(config);
    var $passageEditor = $('#item-editor-item-property-bar');
    fontSelector($passageEditor);
    colorSelector($passageEditor);
    fontSizeChanger($passageEditor);
  };
});
