define('taoMediaManager/qtiCreator/plugins/menu/preview',['jquery', 'i18n', 'core/plugin', 'ui/hider', 'taoMediaManager/previewer/adapter/item/qtiSharedStimulusItem', 'tpl!taoQtiItem/qtiCreator/plugins/button'], function ($, __, pluginFactory, hider, previewerFactory, buttonTpl) {
  'use strict';
  return pluginFactory({
    name: 'preview',
    init() {
      var SharedStimulusCreator = this.getHost();
      SharedStimulusCreator.on('preview', id => {
        previewerFactory.init(id, {
          readOnly: false,
          fullPage: true
        });
      });
      var sharedStimulusConfig = SharedStimulusCreator.getConfig();
      if (sharedStimulusConfig.properties.previewEnabled) {
        this.$element = $(buttonTpl({
          icon: 'preview',
          title: __('Preview the item'),
          text: __('Preview'),
          cssClass: 'preview-trigger',
          testId: 'preview-the-asset'
        })).on('click', e => {
          $(document).trigger('open-preview.qti-item');
          e.preventDefault();
          this.disable();
          SharedStimulusCreator.trigger('preview', SharedStimulusCreator.getSharedStimulusId());
          this.enable();
        });
      }
    },
    render() {
      var $container = this.getAreaBroker().getMenuArea();
      $container.append(this.$element);
    },
    destroy() {
      this.$element.remove();
    },
    enable() {
      this.$element.removeProp('disabled').removeClass('disabled');
    },
    disable() {
      this.$element.prop('disabled', true).addClass('disabled');
    },
    show() {
      hider.show(this.$element);
    },
    hide() {
      hider.hide(this.$element);
    }
  });
});
