define('taoMediaManager/qtiCreator/helper/createDummyItemData',['taoQtiItem/qtiCreator/model/Item'], function (Item) {
  'use strict';

  var _generateIdentifier = function _generateIdentifier(uri) {
    var pos = uri.lastIndexOf('#');
    return uri.substr(pos + 1);
  };
  var creatorDummyItemData = function creatorDummyItemData(sharedStimulusData) {
    var newItem = new Item().id(_generateIdentifier(sharedStimulusData.id)).attr('title', sharedStimulusData.name);
    newItem.data('new', true);
    newItem.data('dummy', true);
    var itemData = Object.assign({}, newItem);
    delete itemData.bdy;
    delete itemData.rootElement;
    itemData.body = sharedStimulusData.body.body;
    itemData.qtiClass = 'assessmentItem';
    itemData.responseProcessing = {
      attributes: {},
      qtiClass: "responseProcessing",
      responseRules: [],
      serial: "response_".concat(sharedStimulusData.body.serial)
    };
    itemData.response = {};
    if (sharedStimulusData.body.attributes['xml:lang']) {
      itemData.attributes['xml:lang'] = sharedStimulusData.body.attributes['xml:lang'];
    }
    if (sharedStimulusData.body.attributes.class) {
      itemData.attributes.class = sharedStimulusData.body.attributes.class;
    }
    return itemData;
  };
  return creatorDummyItemData;
});
